prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org rdfs:label ?orgLabel . }
  FILTER(CONTAINS(STR(?model), "0cad2ceffcad428aab5664a733b078e6"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "0cad2cef") || CONTAINS(LCASE(STR(?normId)), "0cad2cef") || CONTAINS(STR(?model), "0cad2cef"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gateway ?gatewayName ?gatewayDirection ?instantiate ?eventGatewayType ?choreoName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0cad2ceffcad428aab5664a733b078e6" .
  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  ?gateway a bboExt:EventBasedGateway .
  ?gateway tai:belongsTo ?choreo .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDirection . }
  OPTIONAL { ?gateway bboExt:instantiate ?instantiate . }
  OPTIONAL { ?gateway bboExt:eventGatewayType ?eventGatewayType . }
}
LIMIT 25
